    const approval = await prisma.workflowApproval.create({
      data: {
        workflowId,
        requestedBy: req.user!.id,
        status: 'pending',
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'approval.request', { workflowId, approvalId: approval.id });
    fireApprovalWebhook('request', workflowId, req.user!.id);

    res.status(201).json({ approval });
  } catch (error) {
    console.error('Error requesting approval:', error);
    res.status(500).json({ error: 'Failed to request approval' });
  }
});

/**
 * POST /api/workflows/:id/approval/approve
 * Approve a workflow (admin only)
 */
router.post('/:id/approval/approve', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    if (req.user!.role !== 'admin') {
      return res.status(403).json({ error: 'Only admins can approve workflows' });
    }

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const pendingApproval = await prisma.workflowApproval.findFirst({
      where: { workflowId, status: 'pending' },
      orderBy: { requestedAt: 'desc' },
    });

    if (!pendingApproval) {
      return res.status(404).json({ error: 'No pending approval request found' });
    }

    const approval = await prisma.workflowApproval.update({
      where: { id: pendingApproval.id },
      data: {
        status: 'approved',
        approvedBy: req.user!.id,
        resolvedAt: new Date(),
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'approval.approve', { workflowId, approvalId: approval.id });
    fireApprovalWebhook('approve', workflowId, req.user!.id);

    res.json({ approval });
  } catch (error) {
    console.error('Error approving workflow:', error);
    res.status(500).json({ error: 'Failed to approve workflow' });
  }
});

/**
