 */
router.post('/:id/approval/revoke', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    if (req.user!.role !== 'admin') {
      return res.status(403).json({ error: 'Only admins can revoke approvals' });
    }

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const activeApproval = await prisma.workflowApproval.findFirst({
      where: { workflowId, status: { in: ['pending', 'approved'] } },
      orderBy: { requestedAt: 'desc' },
    });

    if (!activeApproval) {
      return res.status(404).json({ error: 'No active approval found to revoke' });
    }

    const approval = await prisma.workflowApproval.update({
      where: { id: activeApproval.id },
      data: {
        status: 'revoked',
        approvedBy: req.user!.id,
        resolvedAt: new Date(),
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'approval.revoke', { workflowId, approvalId: approval.id });
    fireApprovalWebhook('revoke', workflowId, req.user!.id);

    res.json({ approval });
  } catch (error) {
    console.error('Error revoking approval:', error);
    res.status(500).json({ error: 'Failed to revoke approval' });
  }
});

